const COLORS = ['#2B5B84', '#D96C4A', '#5C8065', '#E6B54A', '#7A5C7F', '#472825', '#96786F'];

let filtered = [...RAW];
let sortKey = 'id', sortAsc = true;
let page = 1;
const PAGE_SIZE = 12;

let charts = {};

function count(arr, key) {
    return arr.reduce((acc, r) => { acc[r[key]] = (acc[r[key]] || 0) + 1; return acc; }, {});
}
function avg(arr, key) {
    return arr.length ? (arr.reduce((s, r) => s + r[key], 0) / arr.length).toFixed(1) : 0;
}

function applyFilters() {
    const course = document.getElementById('f-course').value;
    const level = document.getElementById('f-level').value;
    const gender = document.getElementById('f-gender').value;
    const prof = document.getElementById('f-profession').value;
    const rating = document.getElementById('f-rating').value;
    filtered = RAW.filter(r =>
        (!course || r.course_name === course) &&
        (!level || r.course_level === level) &&
        (!gender || r.gender === gender) &&
        (!prof || r.profession === prof) &&
        (!rating || r.rating_course == rating)
    );
    page = 1;
    updateAll();
}

function resetFilters() {
    ['f-course', 'f-level', 'f-gender', 'f-profession', 'f-rating'].forEach(id => document.getElementById(id).value = '');
    document.getElementById('search-input').value = '';
    filtered = [...RAW];
    page = 1;
    updateAll();
}

function updateAll() {
    updateKPIs();
    updateCharts();
    renderTable();
    document.getElementById('shown-count').textContent = filtered.length;
}

function updateKPIs() {
    document.getElementById('kpi-total').textContent = filtered.length;
    document.getElementById('kpi-rating').textContent = avg(filtered, 'rating_course');
    const courses = new Set(filtered.map(r => r.course_name));
    document.getElementById('kpi-courses').textContent = courses.size;
    const lvlCount = count(filtered, 'course_level');
    const topLvl = Object.entries(lvlCount).sort((a, b) => b[1] - a[1])[0];
    if (topLvl) {
        const labels = { beginner: 'Beginner', intermediate: 'Intermediate', advanced: 'Advanced' };
        document.getElementById('kpi-top-level').textContent = labels[topLvl[0]] || topLvl[0];
        document.getElementById('kpi-top-level-pct').textContent = Math.round(topLvl[1] / filtered.length * 100) + '% del total';
    }
}

function mkChart(id, cfg) {
    if (charts[id]) charts[id].destroy();
    const ctx = document.getElementById(id).getContext('2d');
    charts[id] = new Chart(ctx, cfg);
}

function updateCharts() {
    // 1. Estudiantes por curso (barras horizontales)
    const byC = count(filtered, 'course_name');
    const cLabels = Object.keys(byC).sort((a, b) => byC[b] - byC[a]);
    const cVals = cLabels.map(k => byC[k]);
    mkChart('chart-courses', {
        type: 'bar',
        data: { labels: cLabels, datasets: [{ label: 'Estudiantes', data: cVals, backgroundColor: COLORS.slice(0, cLabels.length), borderRadius: 5, borderSkipped: false }] },
        options: { indexAxis: 'y', responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { color: 'rgba(71,40,37,0.1)' }, ticks: { color: '#96786F' } }, y: { grid: { display: false }, ticks: { color: '#472825', font: { size: 11 } } } } }
    });

    // 2. Dona por nivel
    const byL = count(filtered, 'course_level');
    const lvlOrder = ['beginner', 'intermediate', 'advanced'];
    const lvlLabels = lvlOrder.filter(k => byL[k]);
    const lvlVals = lvlLabels.map(k => byL[k] || 0);
    const lvlColors = ['#2B5B84', '#D96C4A', '#5C8065', '#E6B54A', '#7A5C7F', '#472825', '#96786F'];
    mkChart('chart-level', {
        type: 'doughnut',
        data: { labels: lvlLabels.map(l => ({ beginner: 'Beginner', intermediate: 'Intermediate', advanced: 'Advanced' }[l])), datasets: [{ data: lvlVals, backgroundColor: lvlColors, borderWidth: 0, hoverOffset: 8 }] },
        options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { color: '#472825', padding: 16, font: { size: 12 }, usePointStyle: true } }, tooltip: { callbacks: { label: ctx => ' ' + ctx.label + ': ' + ctx.raw + ' (' + Math.round(ctx.raw / filtered.length * 100) + '%)' } } } }
    });

    // 3. Género (pastel)
    const byG = count(filtered, 'gender');
    mkChart('chart-gender', {
        type: 'pie',
        data: { labels: ['Masculino', 'Femenino'], datasets: [{ data: [byG['M'] || 0, byG['F'] || 0], backgroundColor: ['#2B5B84', '#D96C4A'], borderWidth: 0, hoverOffset: 6 }] },
        options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { color: '#472825', font: { size: 11 }, usePointStyle: true } }, tooltip: { callbacks: { label: ctx => ' ' + ctx.label + ': ' + ctx.raw + ' (' + Math.round(ctx.raw / filtered.length * 100) + '%)' } } } }
    });

    // 4. Rating promedio por nivel
    const lvlRating = lvlOrder.map(l => {
        const arr = filtered.filter(r => r.course_level === l);
        return arr.length ? +(arr.reduce((s, r) => s + r.rating_course, 0) / arr.length).toFixed(2) : 0;
    });
    mkChart('chart-rating-level', {
        type: 'bar',
        data: { labels: ['Beginner', 'Intermediate', 'Advanced'], datasets: [{ label: 'Rating promedio', data: lvlRating, backgroundColor: lvlColors, borderRadius: 6, borderSkipped: false }] },
        options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { display: false }, ticks: { color: '#96786F' } }, y: { min: 0, max: 5, grid: { color: 'rgba(71,40,37,0.1)' }, ticks: { color: '#96786F', stepSize: 1 } } } }
    });

    // 5. Profesiones (horizontal)
    const byP = count(filtered, 'profession');
    const pLabels = Object.keys(byP).sort((a, b) => byP[b] - byP[a]).slice(0, 6);
    const short = l => l.length > 18 ? l.slice(0, 16) + '…' : l;
    mkChart('chart-prof', {
        type: 'bar',
        data: { labels: pLabels.map(short), datasets: [{ label: '', data: pLabels.map(k => byP[k]), backgroundColor: '#5C8065', borderRadius: 4, borderSkipped: false }] },
        options: { indexAxis: 'y', responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { color: 'rgba(71,40,37,0.1)' }, ticks: { color: '#96786F' } }, y: { grid: { display: false }, ticks: { color: '#472825', font: { size: 10 } } } } }
    });

    // 6. Registros por mes (línea)
    const months = {};
    filtered.forEach(r => {
        const m = r.registration_date.slice(0, 7);
        months[m] = (months[m] || 0) + 1;
    });
    const mKeys = Object.keys(months).sort();
    mkChart('chart-time', {
        type: 'line',
        data: { labels: mKeys, datasets: [{ label: 'Registros', data: mKeys.map(k => months[k]), borderColor: '#2B5B84', backgroundColor: 'rgba(43,91,132,0.1)', tension: 0.4, fill: true, pointRadius: 3, pointBackgroundColor: '#2B5B84' }] },
        options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { display: false }, ticks: { color: '#96786F', maxTicksLimit: 10, maxRotation: 45 } }, y: { grid: { color: 'rgba(71,40,37,0.1)' }, ticks: { color: '#96786F' } } } }
    });

    // 7. Rating promedio por curso (barras)
    const courseNames = [...new Set(RAW.map(r => r.course_name))];
    const crRatings = courseNames.map(c => {
        const arr = filtered.filter(r => r.course_name === c);
        return arr.length ? +(arr.reduce((s, r) => s + r.rating_course, 0) / arr.length).toFixed(2) : null;
    });
    const validPairs = courseNames.map((c, i) => ({ c, v: crRatings[i] })).filter(p => p.v !== null).sort((a, b) => b.v - a.v);
    mkChart('chart-rating-course', {
        type: 'bar',
        data: { labels: validPairs.map(p => p.c.length > 14 ? p.c.slice(0, 12) + '…' : p.c), datasets: [{ label: 'Rating', data: validPairs.map(p => p.v), backgroundColor: COLORS, borderRadius: 4, borderSkipped: false }] },
        options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { display: false }, ticks: { color: '#96786F', font: { size: 10 }, maxRotation: 45 } }, y: { min: 0, max: 5, grid: { color: 'rgba(71,40,37,0.1)' }, ticks: { color: '#96786F', stepSize: 1 } } } }
    });
}

// TABLE
function starsHTML(n) {
    return '<span class="stars">' + '★'.repeat(n) + '☆'.repeat(5 - n) + '</span>';
}
function badgeLevel(l) {
    const cls = l === 'advanced' ? 'adv' : l === 'intermediate' ? 'int' : 'beg';
    const lbl = { advanced: 'Advanced', intermediate: 'Intermediate', beginner: 'Beginner' }[l] || l;
    return `<span class="badge badge-${cls}">${lbl}</span>`;
}

function getTableData() {
    const q = document.getElementById('search-input').value.toLowerCase();
    let data = filtered.filter(r =>
        !q || (r.first_name + ' ' + r.last_name + ' ' + r.course_name + ' ' + r.email).toLowerCase().includes(q)
    );
    data = data.sort((a, b) => {
        const av = a[sortKey], bv = b[sortKey];
        if (av < bv) return sortAsc ? -1 : 1;
        if (av > bv) return sortAsc ? 1 : -1;
        return 0;
    });
    return data;
}

function renderTable() {
    const data = getTableData();
    const total = data.length;
    const start = (page - 1) * PAGE_SIZE;
    const slice = data.slice(start, start + PAGE_SIZE);
    const tbody = document.getElementById('table-body');
    tbody.innerHTML = slice.map(r => `
    <tr>
      <td style="color:var(--muted)">${r.id}</td>
      <td><strong style="color:var(--text)">${r.first_name} ${r.last_name}</strong><br><span style="font-size:0.72rem;color:var(--muted)">${r.email}</span></td>
      <td>${r.course_name}</td>
      <td>${badgeLevel(r.course_level)}</td>
      <td style="color:var(--muted);font-size:0.78rem">${r.profession}</td>
      <td style="text-align:center">${r.gender === 'M' ? '♂' : '♀'}</td>
      <td>${starsHTML(r.rating_course)}</td>
      <td style="color:var(--muted);font-size:0.78rem">${r.registration_date}</td>
    </tr>`).join('');
    const pages = Math.ceil(total / PAGE_SIZE);
    document.getElementById('pag-info').textContent = `${start + 1}–${Math.min(start + PAGE_SIZE, total)} de ${total}`;
    document.getElementById('btn-prev').disabled = page <= 1;
    document.getElementById('btn-next').disabled = page >= pages;
}

function changePage(d) { page += d; renderTable(); }
function sortTable(k) { if (sortKey === k) sortAsc = !sortAsc; else { sortKey = k; sortAsc = true; } page = 1; renderTable(); }

// INIT selects y event listeners tras la carga del DOM
document.addEventListener("DOMContentLoaded", function () {
    const courses = [...new Set(RAW.map(r => r.course_name))].sort();
    const profs = [...new Set(RAW.map(r => r.profession))].sort();

    const cSel = document.getElementById('f-course');
    courses.forEach(c => { const o = document.createElement('option'); o.value = o.textContent = c; cSel.appendChild(o); });

    const pSel = document.getElementById('f-profession');
    profs.forEach(p => { const o = document.createElement('option'); o.value = o.textContent = p; pSel.appendChild(o); });

    ['f-course', 'f-level', 'f-gender', 'f-profession', 'f-rating'].forEach(id => {
        document.getElementById(id).addEventListener('change', applyFilters);
    });

    updateAll();
});
